input.new_string:
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(scenario: any): unknown {
  const results = scenario.steps.map((step: any) => {
    if (step.items.length === 0) {
      return { premium: 5 };
    }
    const basePremium = BASE_PREMIUMS[step.items[0].type];
    return { premium: Math.ceil(basePremium * 1.1) + 5 };
  });
  return { results };
}

