const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const PROCESSING_FEE = 5;

export function processScenario(scenario: any): unknown {
  const results = scenario.steps.map((step: any) => {
    const policyBasePremium = step.items.reduce((sum: number, item: any) => sum + BASE_PREMIUMS[item.type], 0);
    const firstInsurance = policyBasePremium * 0.1;
    return { premium: Math.ceil(policyBasePremium + firstInsurance + PROCESSING_FEE) };
  });
  return { results };
}

