export function processScenario(scenario: any): unknown {
  const results = scenario.steps.map((step: any) => {
    const componentCounts: Record<string, number> = {};
    let policyBasePremium = 0;

    for (const item of step.items) {
      if (MAIN_ITEM_TYPES.includes(item.type)) {
        policyBasePremium += BASE_PREMIUMS[item.type];
      } else {
        componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
      }
    }

    for (const count of Object.values(componentCounts)) {
      policyBasePremium += count === 3 ? 60 : 25 * count;
    }

    const firstInsurance = policyBasePremium * 0.1;
    return { premium: Math.ceil(policyBasePremium + firstInsurance + PROCESSING_FEE) };
  });
  return { results };
}

