import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - Base Premiums", () => {
    it("should return 5G for empty item list (processing fee only)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote" as const, items: [] }],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 5 }] });
    });
    it("should compute 115G for a single sword (newcomer)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("should compute correct premium for amulet, staff, and potion", () => {
      const amuletScenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      expect(processScenario(amuletScenario)).toEqual({ results: [{ premium: 71 }] });

      const staffScenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      expect(processScenario(staffScenario)).toEqual({ results: [{ premium: 93 }] });

      const potionScenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      expect(processScenario(potionScenario)).toEqual({ results: [{ premium: 49 }] });
    });
    it("should compute 33G for a single rune (component pricing + rounding up)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 33 }] });
    });
    it("should compute 60G for two runes", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 60 }] });
    });
    it("should apply block discount for exactly 3 alike components (71G for 3 runes)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it("should not apply block for 4 components of same type (115G for 4 runes)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" }, { type: "rune" },
              { type: "rune" }, { type: "rune" },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("should not apply block for mixed component types (88G for 2 runes + 1 moonstone)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 88 }] });
    });
    it("should apply separate blocks for different types (137G for 3 runes + 3 moonstones)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune" }, { type: "rune" }, { type: "rune" },
              { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 137 }] });
    });
  });

  describe("Quote - Item Modifiers", () => {
    it("should add 50% cursed surcharge (165G for newcomer cursed sword)", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: true },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 165 }] });
    });
    it("should add 30% surcharge for enchantment level >= 5", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 5, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      expect(result).toEqual({ results: [{ premium: 145 }] });
    });
    it.todo("should stack both cursed and enchantment surcharges on same item");
    it.todo("should scope item surcharges to affected item in multi-item policy");
  });

  describe("Quote - Policy Modifiers", () => {
    it.todo("should apply 20% loyalty discount for >= 2 years with MHPCO");
    it.todo("should apply 15% follow-up discount on second contract");
  });

  describe("Quote - Integration", () => {
    it.todo("should compute 160G for long-standing customer second contract with cursed enchanted sword");
    it.todo("should round premiums up in MHPCO favor (198G for 7 runes)");
  });

  describe("Claim - Payouts", () => {
    it.todo("should subtract 100G deductible from standard damage (400G payout for 500G damage)");
    it.todo("should reimburse component damage minus deductible (100G for 200G rune damage)");
    it.todo("should reimburse at 50% for enchantment >= 8 then deductible (400G for 1000G damage)");
    it.todo("should fully reimburse dragon material then deductible (700G for 800G damage)");
    it.todo("should apply 50% when both dragon and enchantment >= 8 (400G for 1000G damage)");
    it.todo("should apply deductible per damaged item in single event (600G for sword 500G + amulet 300G)");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should track remaining cap across multiple claims");
    it.todo("should round payouts down in MHPCO favor");
  });

  describe("Errors", () => {
    it.todo("should reject unknown item type in quote");
    it.todo("should reject claim for item not in policy");
    it.todo("should reject negative damage amount");
    it.todo("should reject damages exceeding insured item count");
  });
});

