    if (step.op === "quote") {
      const { premium, policy } = processQuote(step, scenario, stepIndex);
      policies[stepIndex] = policy;
      return { premium };
    } else {
      return processClaim(step, policies[step.policy]);
    }
  });
  return { results };
}

