       let totalPayout = 0;
       for (const damage of step.incident.damages) {
         const insuredItem = policy.items.find((i: any) => i.type === damage.itemType);
         if (!insuredItem) { throw new Error(`Item type ${damage.itemType} not in policy`); }
         const reimbursement = insuredItem.enchantment >= 8 ? damage.amount * 0.5 : damage.amount;
         totalPayout += reimbursement - DEDUCTIBLE;
